 6→// Explicit alias map for clustering emergent category variants.
 7→// Targets don't need to be in CANONICAL_FRICTION_CATEGORIES —
 8→// this clusters semantically-equivalent novel categories together.
 9→// Insert alias lookup runs AFTER exact canonical match but BEFORE Levenshtein,
10→// so well-known emergent variants are clustered deterministically.
11→const FRICTION_ALIASES: Record<string, string> = {
12→  // agent orchestration variants → cluster under one emergent name
13→  'agent-lifecycle-issue': 'agent-orchestration-failure',
14→  'agent-communication-failure': 'agent-orchestration-failure',
15→  'agent-communication-breakdown': 'agent-orchestration-failure',
16→  'agent-lifecycle-management': 'agent-orchestration-failure',
17→  'agent-shutdown-failure': 'agent-orchestration-failure',
18→  // rate limit variants → cluster under one emergent name
19→  'api-rate-limit': 'rate-limit-hit',
20→  'rate-limiting': 'rate-limit-hit',
21→  'rate-limited': 'rate-limit-hit',
22→};
23→
24→/** Standard Levenshtein distance between two strings */
25→function levenshtein(a: string, b: string): number {
26→  const m = a.length;
27→  const n = b.length;
28→  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0) as number[]);
29→
30→  for (let i = 0; i <= m; i++) dp[i][0] = i;
31→  for (let j = 0; j <= n; j++) dp[0][j] = j;
32→
33→  for (let i = 1; i <= m; i++) {
34→    for (let j = 1; j <= n; j++) {
35→      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
36→      dp[i][j] = Math.min(
37→        dp[i - 1][j] + 1,
38→        dp[i][j - 1] + 1,
39→        dp[i - 1][j - 1] + cost
40→      );
41→    }
42→  }
43→
44→  return dp[m][n];
45→}
