  5→import { CANONICAL_PATTERN_CATEGORIES } from './prompts.js';
  6→
  7→// Human-readable labels for each canonical category.
  8→// Used in dashboard display (e.g., "structured-planning" → "Structured Planning").
  9→export const PATTERN_CATEGORY_LABELS: Record<string, string> = {
 10→  'structured-planning': 'Structured Planning',
 11→  'incremental-implementation': 'Incremental Implementation',
 12→  'verification-workflow': 'Verification Workflow',
