 76→/** Standard Levenshtein distance between two strings */
 77→function levenshtein(a: string, b: string): number {
 78→  const m = a.length;
 79→  const n = b.length;
 80→  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0) as number[]);
 81→
 82→  for (let i = 0; i <= m; i++) dp[i][0] = i;
 83→  for (let j = 0; j <= n; j++) dp[0][j] = j;
 84→
 85→  for (let i = 1; i <= m; i++) {
 86→    for (let j = 1; j <= n; j++) {
 87→      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
 88→      dp[i][j] = Math.min(
 89→        dp[i - 1][j] + 1,
 90→        dp[i][j - 1] + 1,
 91→        dp[i - 1][j - 1] + cost
 92→      );
 93→    }
 94→  }
 95→
 96→  return dp[m][n];
 97→}
 98→
 99→/**
100→ * Normalize a pattern category to the closest canonical category.
101→ * Returns the original category if no close match is found.
102→ *
103→ * Matching rules (in order):
104→ * 1. Exact match against canonical list → return as-is
105→ * 1.5. Explicit alias match → return alias target (may be non-canonical)
106→ * 2. Levenshtein distance <= 2 → return canonical match
107→ * 3. Substring match (category contains canonical or vice versa) → return canonical
108→ * 4. No match → return original (novel category)
109→ */
110→export function normalizePatternCategory(category: string): string {
111→  const lower = category.toLowerCase();
112→
113→  // 1. Exact match
114→  for (const canonical of CANONICAL_PATTERN_CATEGORIES) {
115→    if (lower === canonical) return canonical;
116→  }
117→
118→  // 1.5. Explicit alias match — clusters emergent category variants deterministically.
119→  if (PATTERN_ALIASES[lower]) return PATTERN_ALIASES[lower];
120→
121→  // 2. Levenshtein distance <= 2
122→  let bestMatch: string | null = null;
123→  let bestDistance = Infinity;
124→  for (const canonical of CANONICAL_PATTERN_CATEGORIES) {
125→    const dist = levenshtein(lower, canonical);
126→    if (dist <= 2 && dist < bestDistance) {
127→      bestDistance = dist;
128→      bestMatch = canonical;
129→    }
130→  }
131→  if (bestMatch) return bestMatch;
132→
133→  // 3. Substring match — only if the shorter string is a significant portion of the longer
134→  // to avoid false positives like "plan" matching "structured-planning"
135→  for (const canonical of CANONICAL_PATTERN_CATEGORIES) {
136→    const shorter = lower.length < canonical.length ? lower : canonical;
137→    const longer = lower.length < canonical.length ? canonical : lower;
138→    if (shorter.length >= 5 && shorter.length / longer.length >= 0.5 && longer.includes(shorter)) {
139→      return canonical;
140→    }
141→  }
142→
143→  // 4. No match — novel category
144→  return category;
145→}
146→
147→/**
148→ * Get a human-readable label for a pattern category.
149→ * Falls back to Title Case conversion for novel categories.
150→ */
151→export function getPatternCategoryLabel(category: string): string {
152→  if (PATTERN_CATEGORY_LABELS[category]) return PATTERN_CATEGORY_LABELS[category];
153→  // Convert kebab-case to Title Case for novel categories
154→  return category
155→    .split('-')
156→    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
157→    .join(' ');
158→}
