  1→// Shared aggregation logic for facets and reflect routes.
  2→// Extracted to avoid ~150 lines of duplication between the two routes.
  3→
  4→import { getDb } from '@code-insights/cli/db/client';
  5→import { normalizeFrictionCategory } from '../llm/friction-normalize.js';
  6→import { normalizePatternCategory, getPatternCategoryLabel } from '../llm/pattern-normalize.js';
  7→
  8→export function buildPeriodFilter(period: string): string | null {
  9→  const now = new Date();
 10→  if (period === '7d') return new Date(now.getTime() - 7 * 86400000).toISOString();
 11→  if (period === '30d') return new Date(now.getTime() - 30 * 86400000).toISOString();
 12→  if (period === '90d') return new Date(now.getTime() - 90 * 86400000).toISOString();
 13→  return null; // 'all'
 14→}
 15→
 16→export function buildWhereClause(
 17→  period: string,
 18→  project?: string,
 19→  source?: string
 20→): { where: string; params: (string | number)[] } {
 21→  // Always exclude soft-deleted sessions from aggregations
 22→  const conditions: string[] = ['s.deleted_at IS NULL'];
 23→  const params: (string | number)[] = [];
 24→
 25→  const periodStart = buildPeriodFilter(period);
 26→  if (periodStart) {
 27→    conditions.push('s.started_at >= ?');
 28→    params.push(periodStart);
 29→  }
 30→  if (project) {
 31→    conditions.push('s.project_id = ?');
 32→    params.push(project);
 33→  }
 34→  if (source) {
 35→    conditions.push('s.source_tool = ?');
 36→    params.push(source);
 37→  }
 38→
 39→  return {
 40→    where: `WHERE ${conditions.join(' AND ')}`,
 41→    params,
 42→  };
 43→}
 44→
 45→export interface AggregatedFrictionCategory {
 46→  category: string;
 47→  count: number;
 48→  avg_severity: number;
 49→  examples: string[];
 50→}
 51→
 52→export interface AggregatedEffectivePattern {
 53→  category: string;
 54→  label: string;            // Human-readable category name (e.g., "Structured Planning")
 55→  frequency: number;
 56→  avg_confidence: number;
 57→  descriptions: string[];   // Representative descriptions, max 10
 58→}
 59→
 60→export interface RateLimitInfo {
 61→  count: number;
 62→  sessionsAffected: number;
 63→  examples: string[];
 64→}
 65→
 66→export interface AggregatedData {
 67→  frictionCategories: AggregatedFrictionCategory[];
 68→  effectivePatterns: AggregatedEffectivePattern[];
 69→  outcomeDistribution: Record<string, number>;
 70→  workflowDistribution: Record<string, number>;
 71→  characterDistribution: Record<string, number>;
 72→  totalSessions: number;
 73→  frictionTotal: number;
 74→  totalAllSessions: number;  // all sessions in scope (not just those with facets)
 75→  rateLimitInfo: RateLimitInfo | null;
 76→  streak: number;            // consecutive days with at least one session (ignores period filter)
 77→  sourceToolCount: number;   // distinct AI tools used within the scope
 78→}
