 80→/**
 81→ * Run all aggregation queries needed for facet analysis and synthesis.
 82→ * Aggregation is done in code (SQL), not by LLMs — LLMs synthesize, they don't count.
 83→ *
 84→ * project and source are passed separately so streak can build its own
 85→ * period-free where clause (streak measures continuity across all time).
 86→ */
 87→export function getAggregatedData(
 88→  db: ReturnType<typeof getDb>,
 89→  where: string,
 90→  params: (string | number)[],
 91→  project?: string,
 92→  source?: string
 93→): AggregatedData {
 94→  const hasWhere = where.length > 0;
 95→  const extraPrefix = hasWhere ? 'AND' : 'WHERE';
 96→
 97→  const frictionCategories = db.prepare(`
 98→    SELECT
 99→      json_extract(je.value, '$.category') as category,
100→      COUNT(*) as count,
101→      AVG(CASE
102→        WHEN json_extract(je.value, '$.severity') = 'high' THEN 3
103→        WHEN json_extract(je.value, '$.severity') = 'medium' THEN 2
104→        ELSE 1
105→      END) as avg_severity,
106→      json_group_array(json_extract(je.value, '$.description')) as examples,
107→      json_group_array(sf.session_id) as session_ids
108→    FROM session_facets sf
109→    JOIN sessions s ON sf.session_id = s.id
110→    CROSS JOIN json_each(sf.friction_points) je
111→    ${where}
112→    GROUP BY category
113→    ORDER BY count DESC, avg_severity DESC
114→  `).all(...params) as Array<{ category: string; count: number; avg_severity: number; examples: string; session_ids: string }>;
115→
116→  // Fetch effective patterns with confidence >= 50.
117→  // Category-based grouping happens in code (post-query) after normalizePatternCategory()
118→  // to handle any LLM variants that were stored before normalization was applied at write time.
119→  // extraPrefix handles the case where where is '' (tests pass empty string) vs a WHERE clause.
120→  const effectivePatternsRaw = db.prepare(`
121→    SELECT
122→      json_extract(je.value, '$.category') as category,
123→      json_extract(je.value, '$.description') as description,
124→      json_extract(je.value, '$.confidence') as confidence
125→    FROM session_facets sf
126→    JOIN sessions s ON sf.session_id = s.id
127→    CROSS JOIN json_each(sf.effective_patterns) je
128→    ${where}
129→    ${extraPrefix} json_extract(je.value, '$.confidence') >= 50
130→    ORDER BY json_extract(je.value, '$.confidence') DESC
131→  `).all(...params) as Array<{ category: string | null; description: string | null; confidence: number | null }>;
132→
133→  const outcomeDistribution = db.prepare(`
134→    SELECT outcome_satisfaction, COUNT(*) as count
135→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
136→    ${where}
137→    GROUP BY outcome_satisfaction
138→  `).all(...params) as Array<{ outcome_satisfaction: string; count: number }>;
139→
140→  const workflowDistribution = db.prepare(`
141→    SELECT workflow_pattern, COUNT(*) as count
142→    FROM session_facets sf JOIN sessions s ON sf.session_id = s.id
143→    ${where}
144→    ${extraPrefix} sf.workflow_pattern IS NOT NULL
145→    GROUP BY workflow_pattern
146→  `).all(...params) as Array<{ workflow_pattern: string; count: number }>;
147→
148→  const characterDistribution = db.prepare(`
149→    SELECT session_character, COUNT(*) as count
150→    FROM sessions s
151→    ${where}
152→    ${extraPrefix} s.session_character IS NOT NULL
153→    GROUP BY session_character
154→  `).all(...params) as Array<{ session_character: string; count: number }>;
155→
156→  const totalRow = db.prepare(
157→    `SELECT COUNT(*) as count FROM session_facets sf JOIN sessions s ON sf.session_id = s.id ${where}`
158→  ).get(...params) as { count: number };
159→
160→  const totalAllRow = db.prepare(
161→    `SELECT COUNT(*) as count FROM sessions s ${where}`
162→  ).get(...params) as { count: number };
163→
164→  // Parse examples and session_ids from json_group_array output, then normalize via alias + Levenshtein clustering
165→  const parsedFriction = frictionCategories.map(fc => ({
166→    ...fc,
167→    examples: JSON.parse(fc.examples) as string[],
168→    session_ids: JSON.parse(fc.session_ids) as string[],
169→  }));
170→
171→  const normalizedFriction = new Map<string, { count: number; total_severity: number; examples: string[]; session_ids: string[] }>();
172→  for (const fc of parsedFriction) {
173→    const normalized = normalizeFrictionCategory(fc.category);
174→    const existing = normalizedFriction.get(normalized);
175→    if (existing) {
176→      existing.count += fc.count;
177→      existing.total_severity += fc.avg_severity * fc.count;
178→      existing.examples.push(...fc.examples);
179→      existing.session_ids.push(...fc.session_ids);
180→    } else {
181→      normalizedFriction.set(normalized, {
182→        count: fc.count,
183→        total_severity: fc.avg_severity * fc.count,
184→        examples: [...fc.examples],
185→        session_ids: [...fc.session_ids],
186→      });
187→    }
188→  }
189→
190→  // Partition: separate rate-limit-hit entries from general friction.
191→  // Rate limits are a billing/plan constraint — surfaced as a usage insight, not friction.
192→  // The alias map already normalizes all rate limit variants to "rate-limit-hit".
193→  // A regex sweep catches creative LLM variants ("throttled-by-api", etc.) that bypass
194→  // both the alias map and Levenshtein clustering.
195→  const RATE_LIMIT_CATEGORY = 'rate-limit-hit';
196→  const RATE_LIMIT_REGEX = /rate.?limit|throttl/i;
197→  let rateLimitInfo: RateLimitInfo | null = null;
198→
199→  // Accumulated data for rateLimitInfo, merged from exact match + regex sweep
200→  let rateLimitCount = 0;
201→  let rateLimitSessionIds: string[] = [];
202→  let rateLimitExamples: string[] = [];
203→
204→  const rateLimitEntry = normalizedFriction.get(RATE_LIMIT_CATEGORY);
205→  if (rateLimitEntry) {
206→    rateLimitCount += rateLimitEntry.count;
207→    rateLimitSessionIds.push(...rateLimitEntry.session_ids);
208→    rateLimitExamples.push(...rateLimitEntry.examples);
209→    normalizedFriction.delete(RATE_LIMIT_CATEGORY);
210→  }
211→
212→  // Regex sweep over remaining entries to catch variants the alias map missed
213→  for (const [category, entry] of normalizedFriction) {
214→    if (RATE_LIMIT_REGEX.test(category)) {
215→      rateLimitCount += entry.count;
216→      rateLimitSessionIds.push(...entry.session_ids);
217→      rateLimitExamples.push(...entry.examples);
218→      normalizedFriction.delete(category);
219→    }
220→  }
221→
222→  if (rateLimitCount > 0) {
223→    const uniqueSessions = new Set(rateLimitSessionIds);
224→    rateLimitInfo = {
225→      count: rateLimitCount,
226→      sessionsAffected: uniqueSessions.size,
227→      examples: rateLimitExamples.slice(0, 3),
228→    };
229→  }
230→
231→  const mergedFriction = Array.from(normalizedFriction.entries())
232→    .map(([category, data]) => ({
233→      category,
234→      count: data.count,
235→      avg_severity: data.total_severity / data.count,
236→      examples: data.examples.slice(0, 10),
237→    }))
238→    .sort((a, b) => b.count - a.count || b.avg_severity - a.avg_severity);
239→
240→  // frictionTotal reflects only non-rate-limit friction (rate limits partitioned separately)
241→  const frictionTotal = mergedFriction.reduce((sum, fc) => sum + fc.count, 0);
242→
243→  // Aggregate effective patterns by normalized category.
244→  // Each row from effectivePatternsRaw is a single pattern entry — we group by normalized
245→  // category in code so normalizePatternCategory() can handle LLM variants at query time.
246→  const normalizedPatterns = new Map<string, { total_confidence: number; count: number; descriptions: string[] }>();
247→  for (const row of effectivePatternsRaw) {
248→    // Skip entries with null category or description (malformed JSON in older sessions)
249→    if (!row.category || !row.description) continue;
250→    const normalized = normalizePatternCategory(row.category);
251→    const existing = normalizedPatterns.get(normalized);
252→    if (existing) {
253→      existing.count += 1;
254→      existing.total_confidence += row.confidence ?? 0;
255→      existing.descriptions.push(row.description);
256→    } else {
257→      normalizedPatterns.set(normalized, {
258→        count: 1,
259→        total_confidence: row.confidence ?? 0,
260→        descriptions: [row.description],
261→      });
262→    }
263→  }
264→
265→  const effectivePatterns: AggregatedEffectivePattern[] = Array.from(normalizedPatterns.entries())
266→    .map(([category, data]) => ({
267→      category,
268→      label: getPatternCategoryLabel(category),
269→      frequency: data.count,
270→      avg_confidence: data.count > 0 ? data.total_confidence / data.count : 0,
271→      descriptions: data.descriptions.slice(0, 10),
272→    }))
273→    .sort((a, b) => b.frequency - a.frequency || b.avg_confidence - a.avg_confidence);
274→
275→  // Count distinct source tools within scope (for hero card stat pill)
276→  const sourceToolRow = db.prepare(
277→    `SELECT COUNT(DISTINCT source_tool) as count FROM sessions s ${where}`
278→  ).get(...params) as { count: number };
279→
280→  // Streak: count consecutive days (backward from today) with at least one session.
281→  // Always uses all-time scope — filtering by period would cap streak at the window size.
282→  // Respects project and source filters since those are user-scope constraints.
283→  const { where: streakWhere, params: streakParams } = buildWhereClause('all', project, source);
284→  const sessionDates = db.prepare(
285→    `SELECT DISTINCT date(started_at) as session_date FROM sessions s ${streakWhere} ORDER BY session_date DESC`
286→  ).all(...streakParams) as Array<{ session_date: string }>;
287→
288→  // Compare dates as YYYY-MM-DD strings in UTC to match SQLite's date() output.
289→  // Using toISOString().slice(0,10) avoids local timezone shifting the day boundary.
290→  const todayUTC = new Date().toISOString().slice(0, 10);
291→  const yesterdayUTC = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
292→
293→  let streak = 0;
294→  // baseline is the date we expect for the next streak entry.
295→  // Start at today; if first session is yesterday, reset baseline to yesterday so
296→  // the loop can continue counting backward from there correctly.
297→  let baseline: string | null = null;
298→
299→  for (const { session_date } of sessionDates) {
300→    if (baseline === null) {
301→      // First entry: must be today or yesterday to start an active streak
302→      if (session_date === todayUTC) {
303→        baseline = todayUTC;
304→      } else if (session_date === yesterdayUTC) {
305→        baseline = yesterdayUTC;
306→      } else {
307→        break; // Gap from today — no active streak
308→      }
309→      streak++;
310→    } else {
311→      // Subsequent entries: must be exactly one day before current baseline
312→      const prevDay: Date = new Date((baseline as string) + 'T00:00:00Z');
313→      prevDay.setUTCDate(prevDay.getUTCDate() - 1);
314→      const expectedPrev: string = prevDay.toISOString().slice(0, 10);
315→      if (session_date !== expectedPrev) break;
316→      baseline = expectedPrev;
317→      streak++;
318→    }
319→  }
320→
321→  return {
322→    frictionCategories: mergedFriction,
323→    effectivePatterns,
324→    outcomeDistribution: Object.fromEntries(outcomeDistribution.map(o => [o.outcome_satisfaction, o.count])),
325→    workflowDistribution: Object.fromEntries(workflowDistribution.map(w => [w.workflow_pattern, w.count])),
326→    characterDistribution: Object.fromEntries(characterDistribution.map(ch => [ch.session_character, ch.count])),
327→    totalSessions: totalRow.count,
328→    frictionTotal,
329→    totalAllSessions: totalAllRow.count,
330→    rateLimitInfo,
331→    streak,
332→    sourceToolCount: sourceToolRow.count,
333→  };
334→}
